import { useState } from 'react'
import { products } from '@/data/products'
import { useStore } from '@/store/useStore'

const PRODUCT_POINTS = 5

export default function Product() {
  const [flippedIds, setFlippedIds] = useState<Set<number>>(new Set())
  const [firstFlipIds, setFirstFlipIds] = useState<Set<number>>(new Set())
  const addSectionScore = useStore((s) => s.addSectionScore)

  const handleFlip = (id: number) => {
    const wasFlipped = flippedIds.has(id)
    setFlippedIds((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
    // 只有第一次翻到背面才加分
    if (!wasFlipped && !firstFlipIds.has(id)) {
      setFirstFlipIds(prev => new Set(prev).add(id))
      addSectionScore('product', PRODUCT_POINTS)
    }
  }

  return (
    <div className="page-section flex flex-col items-center justify-center px-4 py-8"
      style={{ background: 'linear-gradient(180deg, #E8F5E9 0%, #C8E6C9 40%, #A5D6A7 100%)' }}>

      <h1 className="text-3xl font-display text-brand-green mb-2 animate-fade-in-up">
        产品家族
      </h1>
      <p className="text-brand-green/50 text-xs mb-4">首次翻转查看 +{PRODUCT_POINTS}分/张</p>

      <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
        {products.map((p, i) => (
          <div key={p.id}
            className={`flip-card cursor-pointer ${flippedIds.has(p.id) ? 'flipped' : ''}`}
            style={{ height: '180px', animationDelay: `${i * 0.1}s` }}
            onClick={() => handleFlip(p.id)}>
            <div className="flip-card-inner">
              <div className="flip-card-front flex flex-col items-center justify-center p-3 shadow-lg hover:scale-105 transition-transform"
                style={{ background: `linear-gradient(135deg, ${p.colorLight}, ${p.color}40)` }}>
                <span className="text-lg font-display drop-shadow-md mb-1" style={{ color: p.color }}>{p.name}</span>
                <span className="px-3 py-1 rounded-full text-xs font-body text-white" style={{ background: p.color }}>{p.flavor}</span>
                {!firstFlipIds.has(p.id) && (
                  <span className="absolute top-2 right-2 bg-brand-yellow text-brand-orange text-[8px] px-1.5 py-0.5 rounded-full font-bold">
                    +{PRODUCT_POINTS}
                  </span>
                )}
              </div>
              <div className="flip-card-back flex flex-col items-center justify-center p-3 shadow-lg"
                style={{ background: p.color }}>
                <p className="text-sm text-white font-body mb-2 text-center leading-relaxed">{p.description}</p>
                <p className="text-xs text-white/80 font-body text-center leading-relaxed">{p.nutrition}</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      <p className="text-xs text-brand-green/60 mt-4 font-body animate-fade-in-up" style={{ animationDelay: '0.5s' }}>
        点击卡片翻转查看详情
      </p>
    </div>
  )
}
