import { useState, useCallback } from 'react'
import { useStore } from '@/store/useStore'

// 可爱的品牌印象图标 - 每个点击+5分
const IMPRESSION_POINTS = 5

const impressionItems = [
  { id: 1, emoji: '🧃', label: 'AD钙奶', color: '#00A850', fact: '国民级儿童饮品，陪伴三代人成长！' },
  { id: 2, emoji: '🥛', label: '鲜牛奶', color: '#FFD23F', fact: '优质奶源，营养满分！' },
  { id: 3, emoji: '🍼', label: '奶瓶', color: '#5BC0EB', fact: '从小喝到大的经典包装！' },
  { id: 4, emoji: '💪', label: '钙力', color: '#FF6B35', fact: '钙+维生素D，骨骼更强壮！' },
  { id: 5, emoji: '⭐', label: '经典', color: '#FFD23F', fact: '28年经典品牌，品质如一！' },
  { id: 6, emoji: '🌈', label: '多彩', color: '#FF9ECD', fact: '多种口味，每种都是快乐！' },
  { id: 7, emoji: '🏫', label: '课间', color: '#5BC0EB', fact: '课间十分钟，AD钙奶最配！' },
  { id: 8, emoji: '🎒', label: '书包', color: '#FF6B35', fact: '书包里永远有一瓶AD钙奶！' },
  { id: 9, emoji: '🌟', label: '童年', color: '#FFD23F', fact: '童年记忆里最甜的味道！' },
  { id: 10, emoji: '🎉', label: '快乐', color: '#FF9ECD', fact: '每一口都是快乐的滋味！' },
  { id: 11, emoji: '🏃', label: '活力', color: '#00A850', fact: '喝完活力满满，继续玩耍！' },
  { id: 12, emoji: '❤️', label: '热爱', color: '#FF6B8A', fact: '对AD钙奶的热爱，从未改变！' },
]

function ParticleBurst({ x, y }: { x: number; y: number }) {
  const particles = Array.from({ length: 6 }, (_, i) => ({
    id: i, angle: (i * 60) * Math.PI / 180,
    color: ['#00A850', '#FFD23F', '#5BC0EB', '#FF6B35', '#FF9ECD', '#33CC66'][i],
  }))
  return (
    <>
      {particles.map((p) => (
        <div key={p.id} className="particle" style={{
          left: x, top: y, width: 6, height: 6, background: p.color,
          transform: `translate(${Math.cos(p.angle) * 30}px, ${Math.sin(p.angle) * 30}px)`,
        }} />
      ))}
    </>
  )
}

export default function Impression() {
  const { addSectionScore, resetSectionScore, setCurrentPage, sectionScores } = useStore()
  const [clickedItems, setClickedItems] = useState<Set<number>>(new Set())
  const [activeFact, setActiveFact] = useState<{ text: string; color: string } | null>(null)
  const [burst, setBurst] = useState<{ x: number; y: number } | null>(null)
  const [earnedScore, setEarnedScore] = useState(0)

  const handleClick = useCallback((item: typeof impressionItems[number], e: React.MouseEvent) => {
    if (clickedItems.has(item.id)) return

    setClickedItems(prev => new Set(prev).add(item.id))
    addSectionScore('impression', IMPRESSION_POINTS)
    setEarnedScore(prev => prev + IMPRESSION_POINTS)
    setBurst({ x: e.nativeEvent.offsetX, y: e.nativeEvent.offsetY })
    setActiveFact({ text: item.fact, color: item.color })

    setTimeout(() => {
      setBurst(null)
      setActiveFact(null)
    }, 1500)
  }, [clickedItems, addSectionScore])

  const handleReset = useCallback(() => {
    resetSectionScore('impression')
    setClickedItems(new Set())
    setEarnedScore(0)
    setActiveFact(null)
  }, [resetSectionScore])

  const allClicked = clickedItems.size === impressionItems.length

  return (
    <section className="page-section bg-brand-white pattern-dots flex flex-col items-center relative overflow-hidden">
      <h2 className="font-display text-3xl text-brand-green mt-6 animate-slide-in-left z-10">
        经典印象
      </h2>
      <p className="text-sm text-brand-green/60 mt-1 z-10">
        点击图案了解品牌故事 +{IMPRESSION_POINTS}分/个
      </p>

      {/* 进度 */}
      <div className="w-full max-w-sm px-6 mt-3 z-10">
        <div className="flex justify-between text-xs text-brand-green/50 mb-1">
          <span>已发现 {clickedItems.size} / {impressionItems.length}</span>
          <span>本轮 +{earnedScore}分</span>
        </div>
        <div className="h-2 bg-brand-green/10 rounded-full overflow-hidden">
          <div className="h-full bg-gradient-to-r from-brand-green to-brand-green-light rounded-full transition-all duration-500"
            style={{ width: `${(clickedItems.size / impressionItems.length) * 100}%` }} />
        </div>
      </div>

      {/* 图标网格 */}
      <div className="w-full max-w-sm px-4 mt-4 z-10">
        <div className="grid grid-cols-4 gap-3">
          {impressionItems.map((item) => {
            const isClicked = clickedItems.has(item.id)
            return (
              <button key={item.id} onClick={(e) => handleClick(item, e)}
                className={`relative flex flex-col items-center justify-center py-3 rounded-2xl transition-all
                  ${isClicked
                    ? 'bg-white shadow-md scale-95'
                    : 'bg-white/70 shadow-sm active:scale-90 hover:shadow-md'
                  }`}>
                <span className={`text-2xl transition-all ${isClicked ? 'opacity-100' : 'animate-float'}`}
                  style={{ animationDelay: `${item.id * 0.2}s` }}>
                  {item.emoji}
                </span>
                <span className={`text-xs mt-1 font-medium ${isClicked ? 'text-brand-green' : 'text-gray-400'}`}>
                  {item.label}
                </span>
                {isClicked && (
                  <span className="absolute -top-1 -right-1 bg-brand-orange text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center">
                    ✓
                  </span>
                )}
                {!isClicked && (
                  <span className="absolute -top-1 -right-1 bg-brand-yellow text-brand-orange text-[8px] px-1 rounded-full font-bold">
                    +{IMPRESSION_POINTS}
                  </span>
                )}
                {burst && isClicked && <ParticleBurst x={burst.x} y={burst.y} />}
              </button>
            )
          })}
        </div>
      </div>

      {/* 知识卡片 */}
      {activeFact && (
        <div className="w-full max-w-sm px-6 mt-3 z-10 animate-fade-in-scale">
          <div className="rounded-xl px-4 py-2.5 text-sm font-medium shadow-sm"
            style={{ background: `${activeFact.color}15`, color: activeFact.color, borderLeft: `3px solid ${activeFact.color}` }}>
            💡 {activeFact.text}
          </div>
        </div>
      )}

      {/* 全部发现 */}
      {allClicked && (
        <div className="w-full max-w-sm px-6 mt-3 z-10 animate-fade-in-scale">
          <div className="bg-white rounded-2xl p-4 shadow-lg text-center">
            <div className="text-3xl mb-1">🎉</div>
            <p className="font-display text-lg text-brand-green">全部发现！</p>
            <p className="text-brand-orange font-bold">+{earnedScore}分</p>
            <div className="flex gap-3 justify-center mt-2">
              <button onClick={handleReset}
                className="px-4 py-1.5 rounded-full bg-gray-200 text-gray-600 font-display text-xs active:scale-95 transition-transform">
                重新探索
              </button>
              <button onClick={() => setCurrentPage(2)}
                className="px-4 py-1.5 rounded-full bg-gradient-to-r from-brand-green to-brand-green-light
                  text-white font-display text-xs shadow-lg active:scale-95 transition-transform">
                继续探索 →
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 scroll-hint text-brand-green/50 z-10">
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
          <path d="M6 9l6 6 6-6" />
        </svg>
      </div>
    </section>
  )
}
