import { create } from 'zustand'

interface DIYDesign {
  color: string
  sticker: string
  text: string
}

interface GameState {
  score: number
  timeLeft: number
  isPlaying: boolean
  dropsCollected: number
}

interface StoreState {
  currentPage: number
  score: number
  // 各环节独立积分追踪
  sectionScores: {
    impression: number  // 经典印象
    product: number     // 产品家族
    flavor: number      // 口味选择
    memory: number      // 童年回忆
    game: number        // 钙力挑战
    ar: number          // AR互动
    quiz: number        // 营养问答
    diy: number         // DIY瓶身
  }
  flavorChoice: string
  diyDesign: DIYDesign
  gameResult: GameState
  quizScore: number
  quizAnswered: number

  setCurrentPage: (page: number) => void
  addScore: (points: number) => void
  addSectionScore: (section: keyof StoreState['sectionScores'], points: number) => void
  resetSectionScore: (section: keyof StoreState['sectionScores']) => void
  setFlavorChoice: (flavor: string) => void
  updateDIYDesign: (design: Partial<DIYDesign>) => void
  setGameResult: (result: Partial<GameState>) => void
  resetGame: () => void
  addQuizScore: () => void
  addQuizAnswered: () => void
  resetQuiz: () => void
}

const initialGameState: GameState = {
  score: 0,
  timeLeft: 30,
  isPlaying: false,
  dropsCollected: 0,
}

export const useStore = create<StoreState>((set) => ({
  currentPage: 0,
  score: 0,
  sectionScores: {
    impression: 0,
    product: 0,
    flavor: 0,
    memory: 0,
    game: 0,
    ar: 0,
    quiz: 0,
    diy: 0,
  },
  flavorChoice: '',
  diyDesign: { color: '#00A850', sticker: 'star', text: '' },
  gameResult: { ...initialGameState },
  quizScore: 0,
  quizAnswered: 0,

  setCurrentPage: (page) => set({ currentPage: page }),
  addScore: (points) => set((state) => ({ score: state.score + points })),
  addSectionScore: (section, points) => set((state) => ({
    score: state.score + points,
    sectionScores: { ...state.sectionScores, [section]: state.sectionScores[section] + points },
  })),
  resetSectionScore: (section) => set((state) => ({
    score: state.score - state.sectionScores[section],
    sectionScores: { ...state.sectionScores, [section]: 0 },
  })),
  setFlavorChoice: (flavor) => set({ flavorChoice: flavor }),
  updateDIYDesign: (design) =>
    set((state) => ({ diyDesign: { ...state.diyDesign, ...design } })),
  setGameResult: (result) =>
    set((state) => ({ gameResult: { ...state.gameResult, ...result } })),
  resetGame: () => set({ gameResult: { ...initialGameState } }),
  addQuizScore: () => set((state) => ({ quizScore: state.quizScore + 1 })),
  addQuizAnswered: () => set((state) => ({ quizAnswered: state.quizAnswered + 1 })),
  resetQuiz: () => set({ quizScore: 0, quizAnswered: 0 }),
}))
