import { useState, useRef, useCallback, useEffect } from 'react'
import { useStore } from '@/store/useStore'

const AR_POINTS = 30

export default function AR() {
  const { addSectionScore, resetSectionScore } = useStore()
  const videoRef = useRef<HTMLVideoElement>(null)
  const [stream, setStream] = useState<MediaStream | null>(null)
  const [cameraActive, setCameraActive] = useState(false)
  const [discovered, setDiscovered] = useState(false)
  const [scanning, setScanning] = useState(false)
  const [showToast, setShowToast] = useState(false)
  const [hasScored, setHasScored] = useState(false)
  const [statusMsg, setStatusMsg] = useState('点击下方按钮启动摄像头扫描AD钙奶瓶身')
  const scanProgressRef = useRef(0)
  const animFrameRef = useRef(0)

  // 停止摄像头
  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop())
      setStream(null)
    }
    setCameraActive(false)
    setScanning(false)
    cancelAnimationFrame(animFrameRef.current)
  }, [stream])

  // 开始扫描（先启动摄像头，成功后再开始扫描动画）
  const handleStartScan = useCallback(async () => {
    setDiscovered(false)
    setError('')
    scanProgressRef.current = 0
    setScanning(true)
    setStatusMsg('正在启动摄像头...')

    try {
      // 直接在点击事件中调用摄像头（必须是用户手势触发）
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: {
          facingMode: 'environment',
          width: { ideal: 640 },
          height: { ideal: 480 }
        },
        audio: false,
      })

      setStream(mediaStream)
      setCameraActive(true)

      // 设置视频源并播放
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream
        try {
          await videoRef.current.play()
        } catch {
          // 某些浏览器需要用户交互才能播放
          videoRef.current.play().catch(() => {})
        }
      }

      setStatusMsg('正在扫描...')

      // 摄像头启动成功，开始3秒扫描
      startScanAnimation()
    } catch (err: any) {
      console.error('Camera error:', err)
      // 摄像头失败，使用模拟模式
      setCameraActive(false)
      if (err.name === 'NotAllowedError') {
        setStatusMsg('摄像头权限被拒绝，使用模拟扫描...')
      } else if (err.name === 'NotFoundError') {
        setStatusMsg('未检测到摄像头，使用模拟扫描...')
      } else {
        setStatusMsg('摄像头不可用，使用模拟扫描...')
      }
      startScanAnimation()
    }
  }, [hasScored, addSectionScore, stream])

  // 扫描动画
  const startScanAnimation = useCallback(() => {
    const startTime = Date.now()
    const animate = () => {
      const elapsed = Date.now() - startTime
      scanProgressRef.current = Math.min(elapsed / 3000, 1)
      if (elapsed < 3000) {
        animFrameRef.current = requestAnimationFrame(animate)
      } else {
        // 扫描完成
        setDiscovered(true)
        setScanning(false)
        stopCamera()
        if (!hasScored) {
          addSectionScore('ar', AR_POINTS)
          setHasScored(true)
        }
        setStatusMsg('发现AD钙奶!')
        setShowToast(true)
        setTimeout(() => setShowToast(false), 2500)
      }
    }
    animFrameRef.current = requestAnimationFrame(animate)
  }, [hasScored, addSectionScore, stopCamera])

  // 重新扫描
  const handleRescan = useCallback(() => {
    resetSectionScore('ar')
    setDiscovered(false)
    setHasScored(false)
    setError('')
    setStatusMsg('点击下方按钮启动摄像头扫描AD钙奶瓶身')
    stopCamera()
  }, [resetSectionScore, stopCamera])

  // 清理
  useEffect(() => {
    return () => {
      if (stream) stream.getTracks().forEach(t => t.stop())
      cancelAnimationFrame(animFrameRef.current)
    }
  }, [stream])

  const [error, setError] = useState('')

  return (
    <div className="page-section flex flex-col items-center justify-center relative"
      style={{ background: 'linear-gradient(180deg, #1a1a2e 0%, #16213e 100%)' }}>

      <h1 className="text-xl font-bold text-white mb-1 z-10"
        style={{ textShadow: '0 0 20px rgba(0,168,80,0.8), 0 0 40px rgba(0,168,80,0.4)' }}>
        AR互动体验
      </h1>
      <p className="text-white/50 text-[10px] mb-2 z-10">扫描AD钙奶瓶身 +{AR_POINTS}分</p>

      {/* 取景框 */}
      <div className="relative w-60 h-72 z-10 rounded-xl overflow-hidden bg-black/30">
        {/* 四角标记 */}
        <div className="absolute top-0 left-0 w-5 h-5 border-t-2 border-l-2 border-green-400 rounded-tl-lg z-20" />
        <div className="absolute top-0 right-0 w-5 h-5 border-t-2 border-r-2 border-green-400 rounded-tr-lg z-20" />
        <div className="absolute bottom-0 left-0 w-5 h-5 border-b-2 border-l-2 border-green-400 rounded-bl-lg z-20" />
        <div className="absolute bottom-0 right-0 w-5 h-5 border-b-2 border-r-2 border-green-400 rounded-br-lg z-20" />

        {/* 摄像头画面 - 始终渲染，通过opacity控制显示 */}
        <video ref={videoRef} autoPlay playsInline muted
          className="absolute inset-0 w-full h-full object-cover z-10"
          style={{ opacity: cameraActive ? 1 : 0 }} />

        {/* 扫描线 */}
        {scanning && (
          <div className="absolute left-2 right-2 h-0.5 bg-green-400 z-20 transition-all"
            style={{ top: `${scanProgressRef.current * 100}%`, boxShadow: '0 0 8px rgba(74,222,128,0.8)' }} />
        )}

        {/* 未开始时的提示 */}
        {!scanning && !discovered && !cameraActive && (
          <div className="absolute inset-0 flex flex-col items-center justify-center z-10">
            <span className="text-4xl mb-2">📷</span>
            <p className="text-white/40 text-[10px] text-center px-4">点击下方按钮<br/>启动摄像头扫描</p>
          </div>
        )}

        {/* 发现后的瓶身 */}
        {discovered && (
          <div className="absolute inset-0 flex items-center justify-center z-20"
            style={{ background: 'rgba(0,0,0,0.3)' }}>
            <div className="text-center animate-fade-in-scale">
              <div className="mx-auto w-14">
                <div className="w-7 h-3.5 bg-white rounded-t-md mx-auto" />
                <div className="w-5 h-2.5 bg-green-500 mx-auto" />
                <div className="w-14 h-21 bg-gradient-to-b from-green-400 to-green-600 rounded-b-lg relative">
                  <div className="absolute top-3 left-1 right-1 h-8 bg-white/90 rounded-sm flex items-center justify-center">
                    <span className="text-green-600 text-[7px] font-bold">AD钙奶</span>
                  </div>
                </div>
              </div>
              <p className="text-green-400 font-bold mt-1.5 text-xs">发现AD钙奶!</p>
            </div>
          </div>
        )}

        <div className="absolute inset-0 border border-white/20 rounded-xl pointer-events-none z-30" />
      </div>

      {/* 状态文字 */}
      <p className="text-white/50 text-[10px] mt-2 z-10 text-center px-8">{statusMsg}</p>

      {/* 发现提示Toast */}
      {showToast && (
        <div className="absolute top-1/3 left-1/2 -translate-x-1/2 bg-green-500 text-white px-3 py-1.5 rounded-full text-xs font-bold shadow-lg z-30 animate-bounce">
          发现AD钙奶! +{AR_POINTS}分
        </div>
      )}

      {/* 按钮 */}
      <div className="mt-2 z-10">
        {!scanning && !discovered && (
          <button onClick={handleStartScan}
            className="px-5 py-2 rounded-full bg-gradient-to-r from-green-500 to-green-400 text-white text-xs font-bold shadow-lg active:scale-95 transition-transform">
            启动摄像头扫描
          </button>
        )}
        {discovered && (
          <button onClick={handleRescan}
            className="px-5 py-2 rounded-full bg-white/20 text-white text-xs font-bold shadow-lg active:scale-95 transition-transform border border-white/30">
            重新扫描
          </button>
        )}
        {scanning && (
          <button onClick={stopCamera}
            className="px-5 py-2 rounded-full bg-red-500/80 text-white text-xs font-bold shadow-lg active:scale-95 transition-transform">
            取消扫描
          </button>
        )}
      </div>
    </div>
  )
}
