import { useState, useRef, useCallback } from 'react'
import { useStore } from '@/store/useStore'

export default function Share() {
  const { score, flavorChoice, diyDesign, quizScore, sectionScores } = useStore()
  const [posterGenerated, setPosterGenerated] = useState(false)
  const [saveStatus, setSaveStatus] = useState('')
  const [showShareMenu, setShowShareMenu] = useState(false)
  const [copyStatus, setCopyStatus] = useState('')
  const canvasRef = useRef<HTMLCanvasElement>(null)

  const generatePoster = useCallback(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    const w = canvas.width
    const h = canvas.height

    // === 绚丽背景 ===
    const bgGrad = ctx.createLinearGradient(0, 0, w * 0.3, h)
    bgGrad.addColorStop(0, '#667eea')
    bgGrad.addColorStop(0.2, '#764ba2')
    bgGrad.addColorStop(0.4, '#f093fb')
    bgGrad.addColorStop(0.6, '#f5576c')
    bgGrad.addColorStop(0.8, '#fda085')
    bgGrad.addColorStop(1, '#00A850')
    ctx.fillStyle = bgGrad
    ctx.fillRect(0, 0, w, h)

    // 光晕
    ctx.globalAlpha = 0.08
    ctx.beginPath(); ctx.arc(w * 0.3, h * 0.15, 200, 0, Math.PI * 2); ctx.fillStyle = '#ffffff'; ctx.fill()
    ctx.beginPath(); ctx.arc(w * 0.7, h * 0.7, 180, 0, Math.PI * 2); ctx.fill()
    ctx.globalAlpha = 1

    // 彩色圆点
    ctx.globalAlpha = 0.1
    const dotColors = ['#ffffff', '#FFD23F', '#5BC0EB', '#FF9ECD', '#FF6B35']
    for (let i = 0; i < 50; i++) {
      ctx.beginPath()
      ctx.arc(Math.random() * w, Math.random() * h, Math.random() * 14 + 3, 0, Math.PI * 2)
      ctx.fillStyle = dotColors[i % dotColors.length]
      ctx.fill()
    }
    ctx.globalAlpha = 1

    // 波浪线
    ctx.save()
    ctx.globalAlpha = 0.06
    ctx.strokeStyle = '#ffffff'
    ctx.lineWidth = 2.5
    for (let row = 0; row < 3; row++) {
      ctx.beginPath()
      const baseY = h * 0.25 + row * h * 0.22
      for (let x = 0; x <= w; x += 4) {
        const y = baseY + Math.sin(x * 0.015 + row * 1.5) * 20
        if (x === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y)
      }
      ctx.stroke()
    }
    ctx.restore()

    // === 品牌标题 ===
    ctx.textAlign = 'center'
    ctx.fillStyle = '#ffffff'
    ctx.font = 'bold 52px "ZCOOL KuaiLe", cursive'
    ctx.shadowColor = 'rgba(0,0,0,0.15)'
    ctx.shadowBlur = 12
    ctx.fillText('哇哈哈AD钙奶', w / 2, 70)
    ctx.shadowBlur = 0
    ctx.font = '24px "Noto Sans SC", sans-serif'
    ctx.fillStyle = '#ffffffdd'
    ctx.fillText('童年味道 · 钙力全开', w / 2, 105)

    // === 瓶身 ===
    const bx = w / 2, by = 160
    const bottleScale = 1.4

    ctx.save()
    ctx.globalAlpha = 0.3
    const glow = ctx.createRadialGradient(bx, by + 100 * bottleScale, 10, bx, by + 100 * bottleScale, 120 * bottleScale)
    glow.addColorStop(0, diyDesign.color); glow.addColorStop(1, 'transparent')
    ctx.fillStyle = glow; ctx.fillRect(bx - 120 * bottleScale, by - 20, 240 * bottleScale, 240 * bottleScale)
    ctx.restore()

    ctx.fillStyle = '#ffffff'
    ctx.shadowColor = 'rgba(0,0,0,0.08)'; ctx.shadowBlur = 5
    ctx.beginPath(); ctx.roundRect(bx - 25 * bottleScale, by - 10, 50 * bottleScale, 28 * bottleScale, 8); ctx.fill(); ctx.shadowBlur = 0

    ctx.fillStyle = diyDesign.color
    ctx.beginPath()
    ctx.moveTo(bx - 20 * bottleScale, by + 18 * bottleScale)
    ctx.lineTo(bx - 20 * bottleScale, by + 42 * bottleScale)
    ctx.quadraticCurveTo(bx - 20 * bottleScale, by + 50 * bottleScale, bx - 32 * bottleScale, by + 55 * bottleScale)
    ctx.lineTo(bx - 32 * bottleScale, by + 62 * bottleScale)
    ctx.lineTo(bx + 32 * bottleScale, by + 62 * bottleScale)
    ctx.lineTo(bx + 32 * bottleScale, by + 55 * bottleScale)
    ctx.quadraticCurveTo(bx + 20 * bottleScale, by + 50 * bottleScale, bx + 20 * bottleScale, by + 42 * bottleScale)
    ctx.lineTo(bx + 20 * bottleScale, by + 18 * bottleScale)
    ctx.closePath(); ctx.fill()

    ctx.beginPath(); ctx.roundRect(bx - 42 * bottleScale, by + 58 * bottleScale, 84 * bottleScale, 140 * bottleScale, [0, 0, 14 * bottleScale, 14 * bottleScale]); ctx.fill()

    ctx.save(); ctx.globalAlpha = 0.3; ctx.fillStyle = '#ffffff'
    ctx.beginPath(); ctx.roundRect(bx - 36 * bottleScale, by + 64 * bottleScale, 18 * bottleScale, 118 * bottleScale, 8); ctx.fill(); ctx.restore()

    ctx.fillStyle = '#ffffffee'
    ctx.beginPath(); ctx.roundRect(bx - 32 * bottleScale, by + 88 * bottleScale, 64 * bottleScale, 55 * bottleScale, 8); ctx.fill()
    ctx.fillStyle = diyDesign.color
    ctx.font = `bold ${16 * bottleScale}px "ZCOOL KuaiLe", cursive`
    ctx.fillText(diyDesign.text || 'AD钙奶', bx, by + 118 * bottleScale)
    ctx.font = `${11 * bottleScale}px "Noto Sans SC", sans-serif`; ctx.fillStyle = '#888888'
    ctx.fillText('哇哈哈', bx, by + 138 * bottleScale)

    ctx.font = `${32 * bottleScale}px serif`
    const stickerMap: Record<string, string> = { star: '⭐', rainbow: '🌈', muscle: '💪', ribbon: '🎀', lion: '🦁', flower: '🌸' }
    ctx.fillText(stickerMap[diyDesign.sticker] || '⭐', bx, by + 175 * bottleScale)

    // === 积分卡片 ===
    const cardY = by + 260 * bottleScale
    ctx.fillStyle = '#ffffffee'
    ctx.shadowColor = 'rgba(0,0,0,0.06)'; ctx.shadowBlur = 14
    ctx.beginPath(); ctx.roundRect(w / 2 - 150, cardY, 300, 170, 18); ctx.fill(); ctx.shadowBlur = 0

    ctx.fillStyle = '#764ba2'
    ctx.font = 'bold 22px "ZCOOL KuaiLe", cursive'
    ctx.fillText('我的互动成绩', w / 2, cardY + 32)

    ctx.fillStyle = '#f5576c'
    ctx.font = 'bold 50px "ZCOOL KuaiLe", cursive'
    ctx.fillText(`${score}`, w / 2, cardY + 85)
    ctx.fillStyle = '#aaaaaa'; ctx.font = '14px "Noto Sans SC", sans-serif'
    ctx.fillText('互动积分', w / 2, cardY + 108)

    ctx.font = '11px "Noto Sans SC", sans-serif'; ctx.fillStyle = '#888888'
    const sectionTexts: string[] = []
    if (sectionScores.impression > 0) sectionTexts.push(`印象:${sectionScores.impression}`)
    if (sectionScores.product > 0) sectionTexts.push(`产品:${sectionScores.product}`)
    if (sectionScores.flavor > 0) sectionTexts.push(`口味:${sectionScores.flavor}`)
    if (sectionScores.memory > 0) sectionTexts.push(`回忆:${sectionScores.memory}`)
    if (sectionScores.game > 0) sectionTexts.push(`挑战:${sectionScores.game}`)
    if (sectionScores.ar > 0) sectionTexts.push(`AR:${sectionScores.ar}`)
    if (sectionScores.quiz > 0) sectionTexts.push(`问答:${sectionScores.quiz}`)
    if (sectionScores.diy > 0) sectionTexts.push(`DIY:${sectionScores.diy}`)
    if (sectionTexts.length > 0) ctx.fillText(sectionTexts.join(' | '), w / 2, cardY + 132)

    if (flavorChoice) {
      ctx.fillText(`最爱: ${flavorChoice}`, w / 2, cardY + 152)
    }

    // 底部
    const footerY = h - 50
    ctx.fillStyle = '#ffffffcc'; ctx.font = '15px "ZCOOL KuaiLe", cursive'
    ctx.fillText('长按保存 · 分享给好友', w / 2, footerY)
    ctx.fillStyle = '#ffffff60'; ctx.font = '11px "Noto Sans SC", sans-serif'
    ctx.fillText('哇哈哈AD钙奶互动广告', w / 2, footerY + 22)

    setPosterGenerated(true)
  }, [score, flavorChoice, diyDesign, quizScore, sectionScores])

  // 保存图片到本地
  const handleSave = useCallback(async () => {
    const canvas = canvasRef.current
    if (!canvas) return

    setSaveStatus('saving')
    try {
      // 方式1: 使用Web Share API分享图片文件（移动端最可靠）
      if (navigator.canShare && navigator.share) {
        try {
          const blob = await new Promise<Blob | null>((resolve) => canvas.toBlob(resolve, 'image/png', 1.0))
          if (blob) {
            const file = new File([blob], 'wahaha-poster.png', { type: 'image/png' })
            const shareData = { files: [file], title: '哇哈哈AD钙奶海报' }
            if (navigator.canShare(shareData)) {
              await navigator.share(shareData)
              setSaveStatus('done')
              setTimeout(() => setSaveStatus(''), 2000)
              return
            }
          }
        } catch (err: any) {
          // 用户取消分享，不算失败
          if (err.name === 'AbortError') {
            setSaveStatus('')
            return
          }
        }
      }

      // 方式2: 下载方式（PC端）
      const dataUrl = canvas.toDataURL('image/png')
      const link = document.createElement('a')
      link.download = 'wahaha-ad-calcium-poster.png'
      link.href = dataUrl
      document.body.appendChild(link)
      link.click()
      setTimeout(() => document.body.removeChild(link), 100)

      setSaveStatus('done')
      setTimeout(() => setSaveStatus(''), 2500)
    } catch (err) {
      console.error('保存失败:', err)
      // 方式3: 打开新窗口显示图片，用户可长按保存
      try {
        const dataUrl = canvas.toDataURL('image/png')
        const newWin = window.open('')
        if (newWin) {
          newWin.document.write(`<img src="${dataUrl}" style="max-width:100%" />`)
          newWin.document.title = '长按图片保存'
        }
      } catch {
        setSaveStatus('error')
        setTimeout(() => setSaveStatus(''), 3000)
      }
    }
  }, [])

  // 复制链接
  const handleCopyLink = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(window.location.href)
      setCopyStatus('copied')
    } catch {
      const input = document.createElement('input')
      input.value = window.location.href
      document.body.appendChild(input)
      input.select()
      document.execCommand('copy')
      document.body.removeChild(input)
      setCopyStatus('copied')
    }
    setTimeout(() => setCopyStatus(''), 2000)
  }, [])

  // 系统分享（微信等）
  const handleSystemShare = useCallback(async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: '哇哈哈AD钙奶 - 童年味道 钙力全开',
          text: `我在哇哈哈AD钙奶互动广告中获得了${score}分！快来挑战吧！`,
          url: window.location.href,
        })
      } catch (err: any) {
        if (err.name !== 'AbortError') {
          // 分享失败，回退到复制链接
          handleCopyLink()
        }
      }
    } else {
      // 不支持Web Share API，复制链接
      handleCopyLink()
    }
  }, [score, handleCopyLink])

  return (
    <div className="page-section flex flex-col items-center justify-center p-6"
      style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 30%, #f093fb 60%, #f5576c 80%, #ffd23f 100%)' }}>
      <h2 className="font-display text-3xl text-white mb-1 animate-fade-in-up drop-shadow-lg">分享你的快乐</h2>
      <p className="text-white/80 text-sm mb-5 animate-fade-in-up">生成专属海报，分享给好友</p>

      <div className="relative w-[260px] h-[460px] rounded-3xl overflow-hidden shadow-2xl mb-5 border-2 border-white/30">
        <canvas
          ref={canvasRef}
          width={520}
          height={920}
          className="w-full h-full"
          style={{ display: posterGenerated ? 'block' : 'none' }}
        />
        {!posterGenerated && (
          <div className="w-full h-full bg-white/20 backdrop-blur-sm flex flex-col items-center justify-center gap-3">
            <span className="text-5xl animate-float">🧃</span>
            <p className="text-white font-display text-base">点击生成海报</p>
          </div>
        )}
      </div>

      <div className="flex flex-col gap-3 items-center">
        {!posterGenerated ? (
          <button onClick={generatePoster} className="px-8 py-3 rounded-full font-display text-base text-white
            bg-white/25 backdrop-blur-sm border-2 border-white/40 shadow-xl active:scale-95 transition-transform">
            生成海报
          </button>
        ) : (
          <>
            {/* 保存图片按钮 */}
            <button onClick={handleSave}
              className={`px-8 py-3 rounded-full font-display text-sm shadow-lg active:scale-95 transition-transform backdrop-blur-sm w-48 ${
                saveStatus === 'saving' ? 'bg-gray-300 text-gray-600 cursor-wait' :
                saveStatus === 'done' ? 'bg-green-500 text-white' :
                saveStatus === 'error' ? 'bg-red-400 text-white' :
                'bg-white/90 text-purple-600'
              }`}
              disabled={saveStatus === 'saving'}>
              {saveStatus === 'saving' ? '保存中...' : saveStatus === 'done' ? '已保存!' : saveStatus === 'error' ? '失败,重试' : '保存图片'}
            </button>

            {/* 分享好友按钮 */}
            <button onClick={() => setShowShareMenu(!showShareMenu)}
              className="px-8 py-3 rounded-full bg-pink-500/90 text-white font-display text-sm shadow-lg active:scale-95 transition-transform backdrop-blur-sm w-48">
              分享好友
            </button>

            {/* 分享菜单 */}
            {showShareMenu && (
              <div className="flex flex-col gap-2 w-48 animate-fade-in-up">
                <button onClick={handleSystemShare}
                  className="w-full py-2.5 rounded-full bg-green-500 text-white font-display text-xs shadow-md active:scale-95 transition-transform flex items-center justify-center gap-1">
                  📤 分享到微信/QQ等
                </button>
                <button onClick={handleCopyLink}
                  className={`w-full py-2.5 rounded-full font-display text-xs shadow-md active:scale-95 transition-transform flex items-center justify-center gap-1 ${
                    copyStatus === 'copied' ? 'bg-green-400 text-white' : 'bg-white/80 text-purple-600'
                  }`}>
                  {copyStatus === 'copied' ? '✅ 链接已复制!' : '🔗 复制链接'}
                </button>
              </div>
            )}
          </>
        )}
      </div>

      <p className="mt-3 text-white/60 text-xs">互动积分: {score}</p>
    </div>
  )
}
