import { useRef, useState, useEffect, useCallback } from 'react'
import { useStore } from '@/store/useStore'

// 每收集一个钙滴+10分
const POINTS_PER_DROP = 10

interface Drop {
  x: number
  y: number
  speed: number
  radius: number
  alive: boolean
}

interface Splash {
  x: number
  y: number
  life: number
}

export default function Game() {
  const { setGameResult, resetGame, addSectionScore, resetSectionScore } = useStore()
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const dropsRef = useRef<Drop[]>([])
  const splashesRef = useRef<Splash[]>([])
  const frameRef = useRef(0)
  const timerRef = useRef<ReturnType<typeof setInterval>>()
  const scoreRef = useRef(0)
  const startedRef = useRef(false)
  const [started, setStarted] = useState(false)
  const [ended, setEnded] = useState(false)
  const [displayScore, setDisplayScore] = useState(0)
  const [timeLeft, setTimeLeft] = useState(30)

  const drawDrop = useCallback((ctx: CanvasRenderingContext2D, x: number, y: number, r: number) => {
    ctx.save()
    ctx.beginPath()
    ctx.moveTo(x, y - r * 1.6)
    ctx.bezierCurveTo(x - r * 0.3, y - r * 0.8, x - r, y + r * 0.2, x - r * 0.5, y + r)
    ctx.bezierCurveTo(x - r * 0.2, y + r * 1.3, x + r * 0.2, y + r * 1.3, x + r * 0.5, y + r)
    ctx.bezierCurveTo(x + r, y + r * 0.2, x + r * 0.3, y - r * 0.8, x, y - r * 1.6)
    ctx.closePath()
    const grad = ctx.createRadialGradient(x - r * 0.2, y - r * 0.3, r * 0.1, x, y, r * 1.2)
    grad.addColorStop(0, '#ffffff')
    grad.addColorStop(0.4, '#b8e4f8')
    grad.addColorStop(1, '#5BC0EB')
    ctx.fillStyle = grad
    ctx.fill()
    ctx.beginPath()
    ctx.ellipse(x - r * 0.25, y - r * 0.4, r * 0.15, r * 0.25, -0.3, 0, Math.PI * 2)
    ctx.fillStyle = 'rgba(255,255,255,0.7)'
    ctx.fill()
    ctx.restore()
  }, [])

  const drawSplash = useCallback((ctx: CanvasRenderingContext2D, s: Splash) => {
    const alpha = s.life / 10
    const size = (10 - s.life) * 3
    ctx.save()
    ctx.globalAlpha = alpha
    for (let i = 0; i < 6; i++) {
      const angle = (Math.PI * 2 / 6) * i
      ctx.beginPath()
      ctx.arc(s.x + Math.cos(angle) * size, s.y + Math.sin(angle) * size, 3, 0, Math.PI * 2)
      ctx.fillStyle = '#5BC0EB'
      ctx.fill()
    }
    ctx.restore()
  }, [])

  const gameLoop = useCallback(() => {
    const canvas = canvasRef.current
    if (!canvas || !startedRef.current) return
    const ctx = canvas.getContext('2d')!
    const w = canvas.width
    const h = canvas.height
    ctx.clearRect(0, 0, w, h)

    if (Math.random() < 0.03) {
      dropsRef.current.push({
        x: Math.random() * (w - 60) + 30,
        y: -30,
        speed: 1.0 + Math.random() * 1.0,
        radius: 16 + Math.random() * 8,
        alive: true,
      })
    }

    dropsRef.current.forEach((d) => {
      if (!d.alive) return
      d.y += d.speed
      if (d.y > h + 30) d.alive = false
      else drawDrop(ctx, d.x, d.y, d.radius)
    })
    dropsRef.current = dropsRef.current.filter((d) => d.alive)

    splashesRef.current.forEach((s) => { drawSplash(ctx, s); s.life-- })
    splashesRef.current = splashesRef.current.filter((s) => s.life > 0)

    frameRef.current = requestAnimationFrame(gameLoop)
  }, [drawDrop, drawSplash])

  const handleCanvasInteract = useCallback((clientX: number, clientY: number) => {
    if (!startedRef.current) return
    const canvas = canvasRef.current
    if (!canvas) return
    const rect = canvas.getBoundingClientRect()
    const x = (clientX - rect.left) / rect.width * canvas.width
    const y = (clientY - rect.top) / rect.height * canvas.height

    for (const d of dropsRef.current) {
      if (!d.alive) continue
      const dist = Math.hypot(d.x - x, d.y - y)
      if (dist < d.radius + 25) {
        d.alive = false
        splashesRef.current.push({ x: d.x, y: d.y, life: 10 })
        scoreRef.current += POINTS_PER_DROP
        setDisplayScore(scoreRef.current)
        addSectionScore('game', POINTS_PER_DROP)
        break
      }
    }
  }, [addSectionScore])

  const startGame = useCallback(() => {
    // 重来时清零上一局game环节的分数
    resetSectionScore('game')
    resetGame()
    scoreRef.current = 0
    startedRef.current = true
    setStarted(true)
    setEnded(false)
    setDisplayScore(0)
    setTimeLeft(30)
    dropsRef.current = []
    splashesRef.current = []
    setGameResult({ isPlaying: true, score: 0, timeLeft: 30, dropsCollected: 0 })
  }, [resetGame, setGameResult, resetSectionScore])

  useEffect(() => {
    if (!started || ended) return
    timerRef.current = setInterval(() => {
      setTimeLeft((prev) => {
        if (prev <= 1) {
          clearInterval(timerRef.current)
          startedRef.current = false
          setEnded(true)
          setStarted(false)
          setGameResult({ isPlaying: false, score: scoreRef.current, timeLeft: 0, dropsCollected: scoreRef.current / POINTS_PER_DROP })
          return 0
        }
        return prev - 1
      })
    }, 1000)
    return () => clearInterval(timerRef.current)
  }, [started, ended, setGameResult])

  useEffect(() => {
    if (!started) return
    frameRef.current = requestAnimationFrame(gameLoop)
    return () => cancelAnimationFrame(frameRef.current)
  }, [started, gameLoop])

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const resize = () => { canvas.width = canvas.offsetWidth; canvas.height = canvas.offsetHeight }
    resize()
    window.addEventListener('resize', resize)
    return () => window.removeEventListener('resize', resize)
  }, [])

  return (
    <div className="page-section flex flex-col items-center"
      style={{ background: 'linear-gradient(180deg, #5BC0EB 0%, #ffffff 100%)' }}>
      <h1 className="text-3xl font-bold text-white mt-6 mb-1 drop-shadow-lg font-display">钙力挑战</h1>
      <p className="text-white/80 text-xs mb-2">每收集一个钙滴 +{POINTS_PER_DROP}分</p>

      {started && (
        <div className="w-full px-6 flex justify-between items-center mb-2">
          <span className="text-lg font-bold text-white">🏆 {displayScore}分</span>
          <span className={`text-lg font-bold ${timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-white'}`}>
            ⏱ {timeLeft}s
          </span>
        </div>
      )}

      <div className="relative w-full flex-1">
        <canvas ref={canvasRef} className="w-full h-full"
          style={{ touchAction: 'none', cursor: started ? 'pointer' : 'default' }}
          onMouseDown={(e) => { e.preventDefault(); handleCanvasInteract(e.clientX, e.clientY) }}
          onTouchStart={(e) => { e.preventDefault(); if (e.touches[0]) handleCanvasInteract(e.touches[0].clientX, e.touches[0].clientY) }}
        />
        {!started && !ended && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/20">
            <p className="text-white text-lg mb-1 font-display">点击掉落的钙滴收集它们！</p>
            <p className="text-white/70 text-sm mb-1">鼠标点击 / 触屏均可操作</p>
            <p className="text-brand-yellow text-sm font-bold mb-4">每滴 +{POINTS_PER_DROP}分</p>
            <button onClick={startGame}
              className="px-8 py-3 rounded-full bg-gradient-to-r from-green-500 to-green-400 text-white text-xl font-bold shadow-lg active:scale-95 transition-transform font-display">
              开始挑战
            </button>
          </div>
        )}
        {ended && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/30">
            <div className="bg-white/90 rounded-2xl p-8 flex flex-col items-center shadow-xl">
              <p className="text-2xl font-bold text-blue-600 mb-2 font-display">挑战结束!</p>
              <p className="text-4xl font-bold text-amber-500 mb-2">{displayScore} 分</p>
              <p className="text-gray-600 mb-1">收集了 {displayScore / POINTS_PER_DROP} 滴钙滴</p>
              <p className="text-gray-400 text-xs mb-4">（再来一次仅清零本环节积分）</p>
              <button onClick={startGame}
                className="px-8 py-3 rounded-full bg-gradient-to-r from-blue-500 to-cyan-400 text-white text-lg font-bold shadow-lg active:scale-95 transition-transform font-display">
                再来一次
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}
